class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        int[] answer = new int[n];
        boolean[][] graph = new boolean[n][4];
        for (int[] path : paths) {
            graph[path[0] - 1][path[1] - 1] = true;
            graph[path[1] - 1][path[0] - 1] = true;
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 4; j++) {
                if (!graph[i][j]) {
                    answer[i] = j + 1;
                    for (int k = 0; k < n; k++) {
                        if (graph[k][j]) {
                            graph[k][answer[i] - 1] = true;
                        }
                    }
                    break;
                }
            }
        }
        return answer;
    }
}
